 18→ */
 19→
 20→#include "pj_bridge/bridge_server.hpp"
 21→
 22→#include <spdlog/spdlog.h>
 23→
 24→#include <map>
 25→#include <nlohmann/json.hpp>
 26→#include <unordered_set>
 27→
 28→#include "pj_bridge/message_serializer.hpp"
 29→#include "pj_bridge/protocol_constants.hpp"
 30→
 31→using json = nlohmann::json;
 32→
 33→namespace pj_bridge {
 34→
 35→BridgeServer::BridgeServer(
 36→    std::shared_ptr<TopicSourceInterface> topic_source,
 37→    std::shared_ptr<SubscriptionManagerInterface> subscription_manager,
 38→    std::shared_ptr<MiddlewareInterface> middleware, int port, double session_timeout, double publish_rate)
 39→    : topic_source_(std::move(topic_source)),
 40→      subscription_manager_(std::move(subscription_manager)),
 41→      middleware_(std::move(middleware)),
 42→      port_(port),
 43→      session_timeout_(session_timeout),
 44→      publish_rate_(publish_rate),
 45→      initialized_(false),
 46→      total_messages_published_(0),
 47→      total_bytes_published_(0),
 48→      publish_cycles_(0) {}
 49→
 50→BridgeServer::~BridgeServer() {
 51→  // Shut down the middleware before members are destroyed so that
 52→  // disconnect callbacks (which capture `this`) cannot fire into
 53→  // a partially destroyed BridgeServer.
 54→  if (middleware_) {
 55→    middleware_->shutdown();
 56→  }
 57→}
 58→
 59→bool BridgeServer::initialize() {
 60→  if (initialized_) {
 61→    spdlog::warn("Bridge server already initialized");
 62→    return true;
 63→  }
 64→
 65→  spdlog::info("Initializing bridge server...");
 66→
 67→  message_buffer_ = std::make_shared<MessageBuffer>();
 68→  session_manager_ = std::make_unique<SessionManager>(session_timeout_);
 69→
 70→  spdlog::info("Core components created");
 71→
 72→  // Set the global message callback to feed into message buffer
 73→  subscription_manager_->set_message_callback(
 74→      [this](const std::string& topic_name, std::shared_ptr<std::vector<std::byte>> cdr_data, uint64_t timestamp_ns) {
 75→        {
 76→          std::lock_guard<std::mutex> lock(stats_mutex_);
 77→          topic_receive_counts_[topic_name]++;
 78→        }
 79→        if (message_buffer_) {
 80→          message_buffer_->add_message(topic_name, timestamp_ns, std::move(cdr_data));
 81→        }
 82→      });
 83→
 84→  // Register disconnect callback before middleware init to avoid missing events
 85→  middleware_->set_on_disconnect([this](const std::string& client_id) {
 86→    spdlog::info("Client disconnected: '{}'", client_id);
 87→    cleanup_session(client_id);
 88→  });
 89→
 90→  // Initialize middleware (may start accepting connections immediately)
 91→  auto result = middleware_->initialize(static_cast<uint16_t>(port_));
 92→  if (!result) {
 93→    spdlog::error("Failed to initialize middleware: {}", result.error());
 94→    return false;
 95→  }
 96→  spdlog::info("Middleware initialized (port: {})", port_);
 97→
 98→  if (publish_rate_ <= 0.0) {
 99→    spdlog::error("Invalid publish_rate: {:.1f} (must be > 0)", publish_rate_);
100→    return false;
101→  }
102→
103→  initialized_ = true;
104→  spdlog::info("Bridge server initialization complete");
105→
106→  return true;
107→}
108→
109→bool BridgeServer::process_requests() {
110→  if (!initialized_) {
111→    spdlog::error("Bridge server not initialized");
112→    return false;
113→  }
114→
115→  // Receive request (non-blocking with timeout)
116→  std::vector<uint8_t> request_data;
117→  std::string client_id;
118→  bool received = middleware_->receive_request(request_data, client_id);
119→
120→  if (!received || request_data.empty()) {
121→    return false;
122→  }
123→
124→  std::string request(request_data.begin(), request_data.end());
125→  if (client_id.empty()) {
126→    spdlog::warn("Received request with no client identity");
127→    return true;
128→  }
129→
130→  // Parse request JSON
131→  std::string response;
132→  json request_json;
133→  try {
134→    request_json = json::parse(request);
135→
136→    if (!request_json.contains("command")) {
137→      response = create_error_response("INVALID_REQUEST", "Missing 'command' field", request_json);
138→    } else {
139→      std::string command = request_json["command"];
140→
141→      spdlog::debug("Processing '{}' command from client '{}'", command, client_id);
142→
143→      if (command == "get_topics") {
144→        response = handle_get_topics(client_id, request_json);
145→      } else if (command == "subscribe") {
146→        response = handle_subscribe(client_id, request_json);
147→      } else if (command == "unsubscribe") {
148→        response = handle_unsubscribe(client_id, request_json);
149→      } else if (command == "heartbeat") {
150→        response = handle_heartbeat(client_id, request_json);
151→      } else if (command == "pause") {
152→        response = handle_pause(client_id, request_json);
153→      } else if (command == "resume") {
154→        response = handle_resume(client_id, request_json);
155→      } else {
156→        response = create_error_response("UNKNOWN_COMMAND", "Unknown command: " + command, request_json);
157→      }
158→    }
159→  } catch (const json::exception& e) {
160→    spdlog::error("JSON parse error: {}", e.what());
161→    response = create_error_response("INVALID_JSON", "Failed to parse JSON request", json::object());
162→  } catch (const std::exception& e) {
163→    spdlog::error("Error processing request: {}", e.what());
164→    response = create_error_response("INTERNAL_ERROR", "Internal server error", request_json);
165→  }
166→
167→  // Send response to the specific client
168→  std::vector<uint8_t> response_data(response.begin(), response.end());
169→  if (!middleware_->send_reply(client_id, response_data)) {
170→    spdlog::warn("Failed to send response to client '{}', cleaning up session", client_id);
171→    cleanup_session(client_id);
172→  }
173→  return true;
174→}
175→
176→std::string BridgeServer::handle_get_topics(const std::string& client_id, const nlohmann::json& request) {
177→  if (!session_manager_->session_exists(client_id)) {
178→    session_manager_->create_session(client_id);
179→    spdlog::info("Created new session for client '{}'", client_id);
180→  }
181→
182→  session_manager_->update_heartbeat(client_id);
183→
184→  auto topics = topic_source_->get_topics();
185→
186→  json response;
187→  response["status"] = "success";
188→  response["topics"] = json::array();
189→
190→  for (const auto& topic : topics) {
191→    json topic_entry;
192→    topic_entry["name"] = topic.name;
193→    topic_entry["type"] = topic.type;
194→    response["topics"].push_back(topic_entry);
195→  }
196→
197→  inject_response_fields(response, request);
198→
199→  spdlog::info("Returning {} topics to client '{}'", topics.size(), client_id);
200→
201→  return response.dump();
202→}
203→
204→std::string BridgeServer::handle_subscribe(const std::string& client_id, const nlohmann::json& request) {
205→  if (!session_manager_->session_exists(client_id)) {
206→    session_manager_->create_session(client_id);
207→    spdlog::info("Created new session for client '{}'", client_id);
208→  }
209→
210→  session_manager_->update_heartbeat(client_id);
211→
212→  if (!request.contains("topics")) {
213→    return create_error_response("INVALID_REQUEST", "Missing 'topics' field", request);
214→  }
215→
216→  if (!request["topics"].is_array()) {
217→    return create_error_response("INVALID_REQUEST", "'topics' must be an array", request);
218→  }
219→
220→  auto current_subs = session_manager_->get_subscriptions(client_id);
221→
222→  // Parse requested topics — supports mixed array of strings and objects:
223→  //   ["topic1", {"name": "topic2", "max_rate_hz": 10.0}]
224→  std::unordered_map<std::string, double> requested_topics;
225→  for (const auto& topic : request["topics"]) {
226→    if (topic.is_string()) {
227→      requested_topics[topic.get<std::string>()] = 0.0;
228→    } else if (topic.is_object() && topic.contains("name") && topic["name"].is_string()) {
229→      double rate_hz = 0.0;
230→      if (topic.contains("max_rate_hz") && topic["max_rate_hz"].is_number()) {
231→        rate_hz = topic["max_rate_hz"].get<double>();
232→        if (rate_hz < 0.0) {
233→          rate_hz = 0.0;
234→        }
235→      }
236→      requested_topics[topic["name"].get<std::string>()] = rate_hz;
237→    }
238→  }
239→
240→  // Determine which topics to add (additive model — subscribe only adds, never removes)
241→  std::vector<std::string> topics_to_add;
242→  for (const auto& [topic, rate] : requested_topics) {
243→    if (current_subs.find(topic) == current_subs.end()) {
244→      topics_to_add.push_back(topic);
245→    }
246→  }
247→
248→  // Build topic name → type lookup from topic source
249→  auto available_topics = topic_source_->get_topics();
250→  std::unordered_map<std::string, std::string> topic_types;
251→  for (const auto& topic : available_topics) {
252→    topic_types[topic.name] = topic.type;
253→  }
254→
255→  // Subscribe to new topics — track successes and failures
256→  json schemas = json::object();
257→  json failures = json::array();
258→  std::unordered_set<std::string> successfully_subscribed;
259→
260→  for (const auto& topic_name : topics_to_add) {
261→    if (topic_types.find(topic_name) == topic_types.end()) {
262→      spdlog::warn("Client '{}' requested non-existent topic '{}'", client_id, topic_name);
263→      json failure;
264→      failure["topic"] = topic_name;
265→      failure["reason"] = "Topic does not exist";
266→      failures.push_back(failure);
267→      continue;
268→    }
269→
270→    std::string topic_type = topic_types[topic_name];
271→
272→    // Get schema BEFORE subscribing to avoid corrupting the reference count
273→    // if schema extraction fails after subscribe() increments it.
274→    std::string schema;
275→    try {
276→      schema = topic_source_->get_schema(topic_name);
277→    } catch (const std::exception& e) {
278→      spdlog::error("Failed to get schema for topic '{}': {}", topic_name, e.what());
279→      json failure;
280→      failure["topic"] = topic_name;
281→      failure["reason"] = std::string("Schema extraction failed: ") + e.what();
282→      failures.push_back(failure);
283→      continue;
284→    }
285→
286→    if (schema.empty()) {
287→      spdlog::error("Empty schema for topic '{}' (type: {})", topic_name, topic_type);
288→      json failure;
289→      failure["topic"] = topic_name;
290→      failure["reason"] = "Schema extraction returned empty definition";
291→      failures.push_back(failure);
292→      continue;
293→    }
294→
295→    // Subscribe via subscription manager (ref-counted)
296→    bool success = subscription_manager_->subscribe(topic_name, topic_type);
297→    if (!success) {
298→      spdlog::error("Failed to subscribe to topic '{}'", topic_name);
299→      json failure;
300→      failure["topic"] = topic_name;
301→      failure["reason"] = "Subscription manager failed to create subscription";
302→      failures.push_back(failure);
303→      continue;
304→    }
305→
306→    nlohmann::json schema_obj;
307→    schema_obj["encoding"] = topic_source_->schema_encoding();
308→    schema_obj["definition"] = schema;
309→    schemas[topic_name] = schema_obj;
310→    successfully_subscribed.insert(topic_name);
311→
312→    spdlog::info("Client '{}' subscribed to topic '{}' (type: {})", client_id, topic_name, topic_type);
313→  }
314→
315→  // Update session subscriptions with successfully subscribed topics (additive model)
316→  std::unordered_map<std::string, double> final_subscriptions = current_subs;
317→  for (const auto& topic : successfully_subscribed) {
318→    final_subscriptions[topic] = requested_topics[topic];
319→  }
320→  // Update rates for topics that were already subscribed but may have a new rate
321→  for (const auto& [topic, rate] : requested_topics) {
322→    if (final_subscriptions.find(topic) != final_subscriptions.end()) {
323→      final_subscriptions[topic] = rate;
324→    }
325→  }
326→  session_manager_->update_subscriptions(client_id, final_subscriptions);
327→
328→  // Build response
329→  json response;
330→  if (failures.empty()) {
331→    response["status"] = "success";
332→  } else if (schemas.empty()) {
333→    response["status"] = "error";
334→    response["error_code"] = "ALL_SUBSCRIPTIONS_FAILED";
335→    response["message"] = "Failed to subscribe to all requested topics";
336→  } else {
337→    response["status"] = "partial_success";
338→    response["message"] = "Some subscriptions failed";
339→  }
340→
341→  response["schemas"] = schemas;
342→  if (!failures.empty()) {
343→    response["failures"] = failures;
344→  }
345→
346→  // Include rate limits in response for topics with non-zero rates
347→  json rate_limits = json::object();
348→  for (const auto& [topic, rate] : final_subscriptions) {
349→    if (rate > 0.0) {
350→      rate_limits[topic] = rate;
351→    }
352→  }
353→  if (!rate_limits.empty()) {
354→    response["rate_limits"] = rate_limits;
355→  }
356→
357→  inject_response_fields(response, request);
358→
359→  return response.dump();
360→}
361→
362→std::string BridgeServer::handle_unsubscribe(const std::string& client_id, const nlohmann::json& request) {
363→  if (!session_manager_->session_exists(client_id)) {
364→    session_manager_->create_session(client_id);
365→    spdlog::info("Created new session for client '{}'", client_id);
366→  }
367→
368→  session_manager_->update_heartbeat(client_id);
369→
370→  if (!request.contains("topics") || !request["topics"].is_array()) {
371→    return create_error_response("INVALID_REQUEST", "Missing or invalid 'topics' array", request);
372→  }
373→
374→  auto current_subs = session_manager_->get_subscriptions(client_id);
375→
376→  std::vector<std::string> removed;
377→
378→  for (const auto& topic_item : request["topics"]) {
379→    std::string topic_name;
380→    if (topic_item.is_string()) {
381→      topic_name = topic_item.get<std::string>();
382→    } else {
383→      continue;
384→    }
385→
386→    if (current_subs.find(topic_name) != current_subs.end()) {
387→      subscription_manager_->unsubscribe(topic_name);
388→      current_subs.erase(topic_name);
389→      removed.push_back(topic_name);
390→
391→      spdlog::info("Client '{}' unsubscribed from topic '{}'", client_id, topic_name);
392→    }
393→  }
394→
395→  session_manager_->update_subscriptions(client_id, current_subs);
396→
397→  json response;
398→  response["status"] = "success";
399→  response["removed"] = removed;
400→  inject_response_fields(response, request);
401→
402→  return response.dump();
403→}
404→
405→std::string BridgeServer::handle_heartbeat(const std::string& client_id, const nlohmann::json& request) {
406→  if (!session_manager_->session_exists(client_id)) {
407→    session_manager_->create_session(client_id);
408→    spdlog::info("Created new session for client '{}'", client_id);
409→  }
410→
411→  session_manager_->update_heartbeat(client_id);
412→
413→  spdlog::debug("Heartbeat received from client '{}'", client_id);
414→
415→  json response;
416→  response["status"] = "ok";
417→  inject_response_fields(response, request);
418→
419→  return response.dump();
420→}
421→
422→std::string BridgeServer::handle_pause(const std::string& client_id, const nlohmann::json& request) {
423→  if (!session_manager_->session_exists(client_id)) {
424→    session_manager_->create_session(client_id);
425→    spdlog::info("Created new session for client '{}'", client_id);
426→  }
427→
428→  session_manager_->update_heartbeat(client_id);
429→
430→  if (session_manager_->is_paused(client_id)) {
431→    spdlog::debug("Client '{}' already paused", client_id);
432→    json response;
433→    response["status"] = "ok";
434→    response["paused"] = true;
435→    inject_response_fields(response, request);
436→    return response.dump();
437→  }
438→
439→  session_manager_->set_paused(client_id, true);
440→
441→  // Decrement ref counts for all subscribed topics
442→  auto subs = session_manager_->get_subscriptions(client_id);
443→  for (const auto& [topic, rate] : subs) {
444→    subscription_manager_->unsubscribe(topic);
445→    spdlog::debug("Decremented ref count for topic '{}' (client '{}' paused)", topic, client_id);
446→  }
447→
448→  spdlog::info("Client '{}' paused ({} topics refs decremented)", client_id, subs.size());
449→
450→  json response;
451→  response["status"] = "ok";
452→  response["paused"] = true;
453→  inject_response_fields(response, request);
454→  return response.dump();
455→}
456→
457→std::string BridgeServer::handle_resume(const std::string& client_id, const nlohmann::json& request) {
458→  if (!session_manager_->session_exists(client_id)) {
459→    session_manager_->create_session(client_id);
460→    spdlog::info("Created new session for client '{}'", client_id);
461→  }
462→
463→  session_manager_->update_heartbeat(client_id);
464→
465→  if (!session_manager_->is_paused(client_id)) {
466→    spdlog::debug("Client '{}' not paused", client_id);
467→    json response;
468→    response["status"] = "ok";
469→    response["paused"] = false;
470→    inject_response_fields(response, request);
471→    return response.dump();
472→  }
473→
474→  session_manager_->set_paused(client_id, false);
475→
476→  // Build topic name → type lookup for subscribe calls
477→  auto available_topics = topic_source_->get_topics();
478→  std::unordered_map<std::string, std::string> topic_types;
479→  for (const auto& t : available_topics) {
480→    topic_types[t.name] = t.type;
481→  }
482→
483→  // Increment ref counts for all subscribed topics
484→  auto subs = session_manager_->get_subscriptions(client_id);
485→  for (const auto& [topic, rate] : subs) {
486→    auto type_it = topic_types.find(topic);
487→    if (type_it == topic_types.end()) {
488→      spdlog::warn("Topic '{}' no longer exists, cannot re-subscribe for client '{}'", topic, client_id);
489→      continue;
490→    }
491→    bool ok = subscription_manager_->subscribe(topic, type_it->second);
492→    if (ok) {
493→      spdlog::debug("Incremented ref count for topic '{}' (client '{}' resumed)", topic, client_id);
494→    } else {
495→      spdlog::warn("Topic '{}' subscription failed on resume for client '{}'", topic, client_id);
496→    }
497→  }
498→
499→  spdlog::info("Client '{}' resumed ({} topics refs incremented)", client_id, subs.size());
500→
501→  json response;
502→  response["status"] = "ok";
503→  response["paused"] = false;
504→  inject_response_fields(response, request);
505→  return response.dump();
506→}
