508→void BridgeServer::inject_response_fields(nlohmann::json& response, const nlohmann::json& request) const {
509→  response["protocol_version"] = kProtocolVersion;
510→  if (request.contains("id") && request["id"].is_string()) {
511→    response["id"] = request["id"];
512→  }
513→}
