515→std::string BridgeServer::create_error_response(
516→    const std::string& error_code, const std::string& message, const nlohmann::json& request) const {
517→  json response;
518→  response["status"] = "error";
519→  response["error_code"] = error_code;
520→  response["message"] = message;
521→  inject_response_fields(response, request);
522→
523→  return response.dump();
