539→void BridgeServer::cleanup_session(const std::string& client_id) {
540→  std::lock_guard<std::mutex> lock(cleanup_mutex_);
541→
542→  if (!session_manager_->session_exists(client_id)) {
543→    return;
544→  }
545→
546→  auto subscriptions = session_manager_->get_subscriptions(client_id);
547→  bool was_paused = session_manager_->is_paused(client_id);
548→
549→  // Unsubscribe from all topics (only if not paused — paused clients already decremented ref counts)
550→  if (!was_paused) {
551→    for (const auto& [topic, rate] : subscriptions) {
552→      subscription_manager_->unsubscribe(topic);
553→      spdlog::debug("Unsubscribed client '{}' from topic '{}'", client_id, topic);
554→    }
555→  }
556→
557→  session_manager_->remove_session(client_id);
558→
559→  {
560→    std::lock_guard<std::mutex> sent_lock(last_sent_mutex_);
561→    last_sent_times_.erase(client_id);
562→  }
563→
564→  spdlog::info("Cleaned up session for client '{}' ({} topics unsubscribed)", client_id, subscriptions.size());
565→}
