579→  snapshot.topic_receive_counts = std::move(topic_receive_counts_);
580→  topic_receive_counts_.clear();
581→  snapshot.topic_forward_counts = std::move(topic_forward_counts_);
582→  topic_forward_counts_.clear();
583→  snapshot.publish_cycles = publish_cycles_;
584→  publish_cycles_ = 0;
