588→
589→void BridgeServer::publish_aggregated_messages() {
590→  if (!initialized_) {
591→    return;
592→  }
593→
594→  std::unordered_map<std::string, std::deque<BufferedMessage>> messages;
595→  message_buffer_->move_messages(messages);
596→
597→  if (messages.empty()) {
598→    return;
599→  }
600→
601→  try {
602→    auto active_sessions = session_manager_->get_active_sessions();
603→    if (active_sessions.empty()) {
604→      return;
605→    }
606→
607→    // Group clients by subscription config (topic + rate) to avoid redundant serialization.
608→    using GroupKey = std::map<std::string, int>;
609→    std::map<GroupKey, std::vector<std::string>> subscription_groups;
610→    std::unordered_map<std::string, std::unordered_map<std::string, double>> client_subs;
611→
612→    for (const auto& client_id : active_sessions) {
613→      auto subs = session_manager_->get_subscriptions(client_id);
614→      if (subs.empty()) {
615→        continue;
616→      }
617→      GroupKey key;
618→      for (const auto& [topic, rate_hz] : subs) {
619→        key[topic] = static_cast<int>(rate_hz * 1000);
620→      }
621→      subscription_groups[key].push_back(client_id);
622→      client_subs[client_id] = std::move(subs);
623→    }
624→
625→    size_t total_msg_count = 0;
626→    size_t total_bytes = 0;
627→    std::unordered_map<std::string, uint64_t> forward_counts;
628→
629→    // Collect paused state outside of last_sent_mutex_ to avoid lock ordering issues.
630→    std::unordered_map<std::string, bool> paused_state;
631→    for (const auto& [group_key, client_ids] : subscription_groups) {
632→      for (const auto& client_id : client_ids) {
633→        paused_state[client_id] = session_manager_->is_paused(client_id);
634→      }
635→    }
636→
637→    // Per-group serialized frames, built under last_sent_mutex_ for rate limiting
638→    struct GroupFrame {
639→      std::vector<uint8_t> compressed_data;
640→      size_t msg_count;
641→      std::vector<std::string> client_ids;
642→    };
643→    std::vector<GroupFrame> frames;
644→
645→    {
646→      std::lock_guard<std::mutex> sent_lock(last_sent_mutex_);
647→
648→      for (const auto& [group_key, client_ids] : subscription_groups) {
649→        AggregatedMessageSerializer serializer;
650→        size_t group_msg_count = 0;
651→
652→        const auto& representative_subs = client_subs[client_ids.front()];
653→        auto& rep_last_sent = last_sent_times_[client_ids.front()];
654→
655→        for (const auto& [topic, msgs] : messages) {
656→          auto sub_it = representative_subs.find(topic);
657→          if (sub_it == representative_subs.end()) {
658→            continue;
659→          }
660→
661→          double rate_hz = sub_it->second;
662→          int rate_mhz = static_cast<int>(rate_hz * 1000);
663→
664→          if (rate_mhz == 0) {
665→            for (const auto& msg : msgs) {
666→              serializer.serialize_message(topic, msg.timestamp_ns, msg.data->data(), msg.data->size());
667→              group_msg_count++;
668→              forward_counts[topic]++;
669→            }
670→          } else {
671→            uint64_t min_interval_ns = static_cast<uint64_t>(1'000'000'000'000) / static_cast<uint64_t>(rate_mhz);
672→            uint64_t last_sent = rep_last_sent[topic];
673→
674→            for (const auto& msg : msgs) {
675→              if (msg.timestamp_ns >= last_sent + min_interval_ns) {
676→                serializer.serialize_message(topic, msg.timestamp_ns, msg.data->data(), msg.data->size());
677→                last_sent = msg.timestamp_ns;
678→                group_msg_count++;
679→                forward_counts[topic]++;
680→              }
681→            }
682→            rep_last_sent[topic] = last_sent;
683→          }
684→        }
685→
686→        if (group_msg_count == 0) {
687→          continue;
688→        }
689→
690→        GroupFrame frame;
691→        frame.compressed_data = serializer.finalize();
692→        frame.msg_count = group_msg_count;
693→        frame.client_ids = client_ids;
694→
695→        // Propagate rate-limiting state to other clients in the group
696→        for (const auto& client_id : client_ids) {
697→          if (client_id != client_ids.front()) {
698→            last_sent_times_[client_id] = rep_last_sent;
699→          }
700→        }
701→
702→        frames.push_back(std::move(frame));
703→      }
704→    }  // last_sent_mutex_ released here
705→
706→    // Send frames outside of any lock
707→    for (const auto& frame : frames) {
708→      bool any_sent = false;
709→      for (const auto& client_id : frame.client_ids) {
710→        auto it = paused_state.find(client_id);
711→        if (it != paused_state.end() && it->second) {
712→          continue;
713→        }
714→        if (middleware_->send_binary(client_id, frame.compressed_data)) {
715→          any_sent = true;
716→        } else {
717→          spdlog::debug("Failed to send binary frame to client '{}'", client_id);
718→        }
719→      }
720→
721→      if (any_sent) {
722→        total_msg_count += frame.msg_count;
723→        total_bytes += frame.compressed_data.size();
724→      }
725→    }
726→
727→    if (total_msg_count > 0) {
728→      std::lock_guard<std::mutex> lock(stats_mutex_);
729→      total_messages_published_ += total_msg_count;
730→      total_bytes_published_ += total_bytes;
731→      publish_cycles_++;
732→      for (const auto& [topic, count] : forward_counts) {
733→        topic_forward_counts_[topic] += count;
734→      }
735→    }
736→  } catch (const std::exception& e) {
737→    spdlog::error("Error publishing aggregated messages: {}", e.what());
738→  }
739→}
740→
741→}  // namespace pj_bridge
