 14→ * GNU Affero General Public License for more details.
 15→ *
 16→ * You should have received a copy of the GNU Affero General Public License
 17→ * along with pj_bridge. If not, see <https://www.gnu.org/licenses/>.
 18→ */
 19→
 20→#include "pj_bridge/middleware/websocket_middleware.hpp"
 21→
 22→#include <spdlog/spdlog.h>
 23→
 24→#include <atomic>
 25→#include <thread>
 26→
 27→namespace pj_bridge {
 28→
 29→WebSocketMiddleware::WebSocketMiddleware() : initialized_(false) {}
 30→
 31→WebSocketMiddleware::~WebSocketMiddleware() {
 32→  shutdown();
 33→}
 34→
 35→tl::expected<void, std::string> WebSocketMiddleware::initialize(uint16_t port) {
 36→  std::lock_guard<std::mutex> lock(state_mutex_);
 37→
 38→  if (initialized_) {
 39→    return tl::unexpected<std::string>("WebSocket middleware already initialized");
 40→  }
 41→
 42→  server_ = std::make_shared<ix::WebSocketServer>(port, "0.0.0.0");
 43→
 44→  server_->setOnClientMessageCallback([this](
 45→                                          std::shared_ptr<ix::ConnectionState> connection_state,
 46→                                          ix::WebSocket& web_socket, const ix::WebSocketMessagePtr& msg) {
 47→    {
 48→      std::lock_guard<std::mutex> state_lock(state_mutex_);
 49→      if (!initialized_) {
 50→        return;
 51→      }
 52→    }
 53→
 54→    std::string client_id = connection_state->getId();
 55→
 56→    if (msg->type == ix::WebSocketMessageType::Open) {
 57→      {
 58→        std::lock_guard<std::mutex> clients_lock(clients_mutex_);
 59→        for (const auto& client : server_->getClients()) {
 60→          if (client.get() == &web_socket) {
 61→            clients_[client_id] = client;
 62→            break;
 63→          }
 64→        }
 65→      }
 66→
 67→      ConnectionCallback cb;
 68→      {
 69→        std::lock_guard<std::mutex> state_lock(state_mutex_);
 70→        cb = on_connect_;
 71→      }
 72→      if (cb) {
 73→        cb(client_id);
 74→      }
 75→
 76→    } else if (msg->type == ix::WebSocketMessageType::Close) {
 77→      ConnectionCallback cb;
 78→      {
 79→        std::lock_guard<std::mutex> state_lock(state_mutex_);
 80→        cb = on_disconnect_;
 81→      }
 82→      if (cb) {
 83→        cb(client_id);
 84→      }
 85→
 86→      {
 87→        std::lock_guard<std::mutex> clients_lock(clients_mutex_);
 88→        clients_.erase(client_id);
 89→      }
 90→
 91→    } else if (msg->type == ix::WebSocketMessageType::Message) {
 92→      if (!msg->binary) {
 93→        IncomingRequest req;
 94→        req.client_id = client_id;
 95→        req.data.assign(msg->str.begin(), msg->str.end());
 96→
 97→        {
 98→          std::lock_guard<std::mutex> queue_lock(queue_mutex_);
 99→          incoming_queue_.push(std::move(req));
100→        }
101→        queue_cv_.notify_one();
102→      }
103→    }
104→  });
105→
106→  auto listen_result = server_->listen();
107→  if (!listen_result.first) {
108→    server_.reset();
109→    return tl::unexpected<std::string>(
110→        "Failed to listen on port " + std::to_string(port) + ": " + listen_result.second);
111→  }
112→
113→  server_->start();
114→  initialized_ = true;
115→
116→  return {};
117→}
118→
119→void WebSocketMiddleware::shutdown() {
120→  std::shared_ptr<ix::WebSocketServer> server_to_stop;
121→
122→  {
123→    std::lock_guard<std::mutex> lock(state_mutex_);
124→
125→    if (!initialized_) {
126→      return;
127→    }
128→
129→    initialized_ = false;
130→    on_connect_ = nullptr;
131→    on_disconnect_ = nullptr;
132→    server_to_stop = std::move(server_);
133→  }
134→
135→  queue_cv_.notify_all();
136→
137→  if (server_to_stop) {
138→    // Replace the message callback with a no-op before stopping. The original
139→    // callback captures `this`, so it must not fire after the WebSocketMiddleware
140→    // instance is destroyed (which can happen if the stop thread is detached on timeout).
141→    server_to_stop->setOnClientMessageCallback(
142→        [](std::shared_ptr<ix::ConnectionState>, ix::WebSocket&, const ix::WebSocketMessagePtr&) {});
143→
144→    // Initiate graceful close on all connected clients before calling stop().
145→    spdlog::debug("[shutdown] Pre-closing {} WebSocket client(s)...", server_to_stop->getClients().size());
146→    for (const auto& client : server_to_stop->getClients()) {
147→      client->close();
148→    }
149→
150→    // Run stop() on a dedicated thread with a timeout.
151→    spdlog::debug("[shutdown] Starting server stop thread...");
152→    auto done = std::make_shared<std::atomic<bool>>(false);
153→    std::thread stop_thread([server_to_stop, done]() {
154→      server_to_stop->stop();
155→      done->store(true);
156→    });
157→
158→    auto start = std::chrono::steady_clock::now();
159→    auto deadline = start + std::chrono::seconds(kShutdownTimeoutSeconds);
160→    while (!done->load() && std::chrono::steady_clock::now() < deadline) {
161→      std::this_thread::sleep_for(std::chrono::milliseconds(50));
162→    }
163→    auto elapsed_ms =
164→        std::chrono::duration_cast<std::chrono::milliseconds>(std::chrono::steady_clock::now() - start).count();
165→
166→    if (done->load()) {
167→      stop_thread.join();
168→      spdlog::debug("[shutdown] Server stop completed (took {}ms)", elapsed_ms);
169→    } else {
170→      // Timeout reached. Detach the thread and let it finish in the background.
171→      // The thread captures server_to_stop by shared_ptr, so the server
172→      // will be destroyed when stop() finishes and the thread exits.
173→      // The message callback was already cleared above, so no use-after-free.
174→      spdlog::warn(
175→          "[shutdown] Server stop timed out after {}s ({}ms elapsed), detaching shutdown thread",
176→          kShutdownTimeoutSeconds, elapsed_ms);
177→      stop_thread.detach();
178→    }
179→  }
180→
181→  {
182→    std::lock_guard<std::mutex> clients_lock(clients_mutex_);
183→    clients_.clear();
184→  }
185→
186→  {
187→    std::lock_guard<std::mutex> queue_lock(queue_mutex_);
188→    std::queue<IncomingRequest> empty;
189→    std::swap(incoming_queue_, empty);
190→  }
191→}
192→
193→bool WebSocketMiddleware::receive_request(std::vector<uint8_t>& data, std::string& client_identity) {
194→  {
195→    std::lock_guard<std::mutex> state_lock(state_mutex_);
196→    if (!initialized_) {
197→      return false;
198→    }
199→  }
200→
201→  std::unique_lock<std::mutex> lock(queue_mutex_);
202→
203→  if (!queue_cv_.wait_for(
204→          lock, std::chrono::milliseconds(kReceiveTimeoutMs), [this]() { return !incoming_queue_.empty(); })) {
205→    return false;
206→  }
207→
208→  auto req = std::move(incoming_queue_.front());
209→  incoming_queue_.pop();
210→
211→  data = std::move(req.data);
212→  client_identity = std::move(req.client_id);
213→  return true;
214→}
215→
216→bool WebSocketMiddleware::send_reply(const std::string& client_identity, const std::vector<uint8_t>& data) {
217→  std::lock_guard<std::mutex> lock(clients_mutex_);
218→
219→  auto it = clients_.find(client_identity);
220→  if (it == clients_.end() || !it->second) {
221→    return false;
222→  }
223→
224→  std::string text_data(data.begin(), data.end());
225→  auto send_info = it->second->send(text_data);
226→  return send_info.success;
227→}
228→
229→bool WebSocketMiddleware::send_binary(const std::string& client_identity, const std::vector<uint8_t>& data) {
230→  std::lock_guard<std::mutex> lock(clients_mutex_);
231→
232→  auto it = clients_.find(client_identity);
233→  if (it == clients_.end() || !it->second) {
234→    return false;
235→  }
236→
237→  std::string binary_data(reinterpret_cast<const char*>(data.data()), data.size());
238→  auto send_info = it->second->sendBinary(binary_data);
239→  return send_info.success;
240→}
241→
242→bool WebSocketMiddleware::publish_data(const std::vector<uint8_t>& data) {
243→  std::lock_guard<std::mutex> lock(clients_mutex_);
244→
245→  if (clients_.empty()) {
246→    return false;
247→  }
248→
249→  std::string binary_data(reinterpret_cast<const char*>(data.data()), data.size());
250→  bool any_sent = false;
251→
252→  for (auto& [client_id, ws] : clients_) {
253→    if (ws) {
254→      auto send_info = ws->sendBinary(binary_data);
255→      if (send_info.success) {
256→        any_sent = true;
257→      }
258→    }
259→  }
260→
261→  return any_sent;
262→}
263→
264→bool WebSocketMiddleware::is_ready() const {
265→  std::lock_guard<std::mutex> lock(state_mutex_);
266→  return initialized_;
267→}
268→
269→void WebSocketMiddleware::set_on_connect(ConnectionCallback callback) {
270→  std::lock_guard<std::mutex> lock(state_mutex_);
271→  on_connect_ = std::move(callback);
272→}
273→
274→void WebSocketMiddleware::set_on_disconnect(ConnectionCallback callback) {
275→  std::lock_guard<std::mutex> lock(state_mutex_);
276→  on_disconnect_ = std::move(callback);
277→}
278→
279→}  // namespace pj_bridge
