138→// Helper: wait for the ix::WebSocket client to reach Open state (up to timeout_ms).
139→static bool wait_for_client_open(ix::WebSocket& client, int timeout_ms = 2000) {
140→  auto deadline = std::chrono::steady_clock::now() + std::chrono::milliseconds(timeout_ms);
