for (const auto& [topic, rate] : requested_topics) {
  if (final_subscriptions.find(topic) != final_subscriptions.end()) {
    final_subscriptions[topic] = rate;
  }
}
session_manager_->update_subscriptions(client_id, final_subscriptions);

