+  server_->process_requests();
+  mock_->pop_reply("client_obj_unsub");
+
+  EXPECT_TRUE(mock_sub_manager_->is_subscribed("/topic_a"));
+
+  // Unsubscribe using object format
+  json unsub;
+  unsub["command"] = "unsubscribe";
