 34→BridgeServer::BridgeServer(
 35→    std::shared_ptr<TopicSourceInterface> topic_source,
 36→    std::shared_ptr<SubscriptionManagerInterface> subscription_manager,
 37→    std::shared_ptr<MiddlewareInterface> middleware, int port, double session_timeout, double publish_rate)
 38→    : topic_source_(std::move(topic_source)),
 39→      subscription_manager_(std::move(subscription_manager)),
 40→      middleware_(std::move(middleware)),
 41→      port_(port),
 42→      session_timeout_(session_timeout),
 43→      publish_rate_(publish_rate),
 44→      initialized_(false),
 45→      total_messages_published_(0),
 46→      total_bytes_published_(0),
 47→      publish_cycles_(0) {}
 48→
 49→BridgeServer::~BridgeServer() {
 50→  // Shut down the middleware before members are destroyed so that
 51→  // disconnect callbacks (which capture `this`) cannot fire into
 52→  // a partially destroyed BridgeServer.
 53→  if (middleware_) {
 54→    middleware_->shutdown();
 55→  }
 56→}
 57→
 58→bool BridgeServer::initialize() {
 59→  if (initialized_) {
 60→    spdlog::warn("Bridge server already initialized");
 61→    return true;
 62→  }
 63→
 64→  spdlog::info("Initializing bridge server...");
 65→
 66→  message_buffer_ = std::make_shared<MessageBuffer>();
 67→  session_manager_ = std::make_unique<SessionManager>(session_timeout_);
 68→
 69→  spdlog::info("Core components created");
 70→
 71→  // Set the global message callback to feed into message buffer
 72→  subscription_manager_->set_message_callback(
 73→      [this](const std::string& topic_name, std::shared_ptr<std::vector<std::byte>> cdr_data, uint64_t timestamp_ns) {
 74→        {
 75→          std::lock_guard<std::mutex> lock(stats_mutex_);
 76→          topic_receive_counts_[topic_name]++;
 77→        }
 78→        if (message_buffer_) {
 79→          message_buffer_->add_message(topic_name, timestamp_ns, std::move(cdr_data));
 80→        }
 81→      });
 82→
 83→  // Register disconnect callback before middleware init to avoid missing events
 84→  middleware_->set_on_disconnect([this](const std::string& client_id) {
 85→    spdlog::info("Client disconnected: '{}'", client_id);
 86→    cleanup_session(client_id);
 87→  });
 88→
 89→  // Initialize middleware (may start accepting connections immediately)
 90→  auto result = middleware_->initialize(static_cast<uint16_t>(port_));
 91→  if (!result) {
 92→    spdlog::error("Failed to initialize middleware: {}", result.error());
 93→    return false;
 94→  }
 95→  spdlog::info("Middleware initialized (port: {})", port_);
 96→
 97→  if (publish_rate_ <= 0.0) {
 98→    spdlog::error("Invalid publish_rate: {:.1f} (must be > 0)", publish_rate_);
 99→    return false;
100→  }
101→
102→  initialized_ = true;
103→  spdlog::info("Bridge server initialization complete");
104→
105→  return true;
106→}
107→
108→bool BridgeServer::process_requests() {
109→  if (!initialized_) {
110→    spdlog::error("Bridge server not initialized");
111→    return false;
112→  }
113→
114→  // Receive request (non-blocking with timeout)
115→  std::vector<uint8_t> request_data;
116→  std::string client_id;
117→  bool received = middleware_->receive_request(request_data, client_id);
118→
119→  if (!received || request_data.empty()) {
120→    return false;
121→  }
122→
123→  std::string request(request_data.begin(), request_data.end());
124→  if (client_id.empty()) {
125→    spdlog::warn("Received request with no client identity");
126→    return true;
127→  }
128→
129→  // Parse request JSON
130→  std::string response;
131→  json request_json;
132→  try {
133→    request_json = json::parse(request);
134→
135→    if (!request_json.contains("command")) {
136→      response = create_error_response("INVALID_REQUEST", "Missing 'command' field", request_json);
137→    } else {
138→      std::string command = request_json["command"];
139→
140→      spdlog::debug("Processing '{}' command from client '{}'", command, client_id);
141→
142→      if (command == "get_topics") {
143→        response = handle_get_topics(client_id, request_json);
144→      } else if (command == "subscribe") {
145→        response = handle_subscribe(client_id, request_json);
146→      } else if (command == "unsubscribe") {
147→        response = handle_unsubscribe(client_id, request_json);
148→      } else if (command == "heartbeat") {
149→        response = handle_heartbeat(client_id, request_json);
150→      } else if (command == "pause") {
151→        response = handle_pause(client_id, request_json);
152→      } else if (command == "resume") {
153→        response = handle_resume(client_id, request_json);
154→      } else {
155→        response = create_error_response("UNKNOWN_COMMAND", "Unknown command: " + command, request_json);
156→      }
157→    }
158→  } catch (const json::exception& e) {
159→    spdlog::error("JSON parse error: {}", e.what());
160→    response = create_error_response("INVALID_JSON", "Failed to parse JSON request", json::object());
161→  } catch (const std::exception& e) {
162→    spdlog::error("Error processing request: {}", e.what());
163→    response = create_error_response("INTERNAL_ERROR", "Internal server error", request_json);
164→  }
165→
166→  // Send response to the specific client
167→  std::vector<uint8_t> response_data(response.begin(), response.end());
168→  if (!middleware_->send_reply(client_id, response_data)) {
169→    spdlog::warn("Failed to send response to client '{}', cleaning up session", client_id);
170→    cleanup_session(client_id);
171→  }
172→  return true;
173→}
174→
175→std::string BridgeServer::handle_get_topics(const std::string& client_id, const nlohmann::json& request) {
176→  if (!session_manager_->session_exists(client_id)) {
177→    session_manager_->create_session(client_id);
178→    spdlog::info("Created new session for client '{}'", client_id);
179→  }
180→
181→  session_manager_->update_heartbeat(client_id);
182→
183→  auto topics = topic_source_->get_topics();
184→
185→  json response;
186→  response["status"] = "success";
187→  response["topics"] = json::array();
188→
189→  for (const auto& topic : topics) {
190→    json topic_entry;
191→    topic_entry["name"] = topic.name;
192→    topic_entry["type"] = topic.type;
193→    response["topics"].push_back(topic_entry);
194→  }
195→
196→  inject_response_fields(response, request);
197→
198→  spdlog::info("Returning {} topics to client '{}'", topics.size(), client_id);
199→
200→  return response.dump();
201→}
202→
203→std::string BridgeServer::handle_subscribe(const std::string& client_id, const nlohmann::json& request) {
204→  if (!session_manager_->session_exists(client_id)) {
205→    session_manager_->create_session(client_id);
206→    spdlog::info("Created new session for client '{}'", client_id);
207→  }
208→
209→  session_manager_->update_heartbeat(client_id);
210→
211→  if (!request.contains("topics")) {
212→    return create_error_response("INVALID_REQUEST", "Missing 'topics' field", request);
213→  }
214→
215→  if (!request["topics"].is_array()) {
216→    return create_error_response("INVALID_REQUEST", "'topics' must be an array", request);
217→  }
218→
219→  auto current_subs = session_manager_->get_subscriptions(client_id);
220→
221→  // Parse requested topics — supports mixed array of strings and objects:
222→  //   ["topic1", {"name": "topic2", "max_rate_hz": 10.0}]
223→  std::unordered_map<std::string, double> requested_topics;
224→  for (const auto& topic : request["topics"]) {
225→    if (topic.is_string()) {
226→      requested_topics[topic.get<std::string>()] = 0.0;
227→    } else if (topic.is_object() && topic.contains("name") && topic["name"].is_string()) {
228→      double rate_hz = 0.0;
229→      if (topic.contains("max_rate_hz") && topic["max_rate_hz"].is_number()) {
230→        rate_hz = topic["max_rate_hz"].get<double>();
231→        if (rate_hz < 0.0) {
232→          rate_hz = 0.0;
233→        }
234→      }
235→      requested_topics[topic["name"].get<std::string>()] = rate_hz;
236→    }
237→  }
238→
239→  // Determine which topics to add (additive model — subscribe only adds, never removes)
240→  std::vector<std::string> topics_to_add;
241→  for (const auto& [topic, rate] : requested_topics) {
242→    if (current_subs.find(topic) == current_subs.end()) {
243→      topics_to_add.push_back(topic);
244→    }
245→  }
246→
247→  // Build topic name → type lookup from topic source
248→  auto available_topics = topic_source_->get_topics();
249→  std::unordered_map<std::string, std::string> topic_types;
250→  for (const auto& topic : available_topics) {
251→    topic_types[topic.name] = topic.type;
252→  }
253→
254→  // Subscribe to new topics — track successes and failures
255→  json schemas = json::object();
256→  json failures = json::array();
257→
258→  for (const auto& topic_name : topics_to_add) {
259→    if (topic_types.find(topic_name) == topic_types.end()) {
260→      spdlog::warn("Client '{}' requested non-existent topic '{}'", client_id, topic_name);
261→      json failure;
262→      failure["topic"] = topic_name;
263→      failure["reason"] = "Topic does not exist";
264→      failures.push_back(failure);
265→      continue;
266→    }
267→
268→    std::string topic_type = topic_types[topic_name];
269→
270→    // Get schema BEFORE subscribing to avoid corrupting the reference count
271→    // if schema extraction fails after subscribe() increments it.
272→    std::string schema;
273→    try {
274→      schema = topic_source_->get_schema(topic_name);
275→    } catch (const std::exception& e) {
276→      spdlog::error("Failed to get schema for topic '{}': {}", topic_name, e.what());
277→      json failure;
278→      failure["topic"] = topic_name;
279→      failure["reason"] = std::string("Schema extraction failed: ") + e.what();
280→      failures.push_back(failure);
281→      continue;
282→    }
283→
284→    if (schema.empty()) {
285→      spdlog::error("Empty schema for topic '{}' (type: {})", topic_name, topic_type);
286→      json failure;
287→      failure["topic"] = topic_name;
288→      failure["reason"] = "Schema extraction returned empty definition";
289→      failures.push_back(failure);
290→      continue;
291→    }
292→
293→    // Subscribe via subscription manager (ref-counted)
294→    bool success = subscription_manager_->subscribe(topic_name, topic_type);
295→    if (!success) {
296→      spdlog::error("Failed to subscribe to topic '{}'", topic_name);
297→      json failure;
298→      failure["topic"] = topic_name;
299→      failure["reason"] = "Subscription manager failed to create subscription";
300→      failures.push_back(failure);
301→      continue;
302→    }
303→
304→    // Immediately add to session. If session is gone (client disconnected
305→    // between subscribe and now), roll back the ref count.
306→    if (!session_manager_->add_subscription(client_id, topic_name, requested_topics[topic_name])) {
307→      spdlog::warn("Session gone for client '{}', rolling back subscribe for '{}'", client_id, topic_name);
308→      subscription_manager_->unsubscribe(topic_name);
309→      continue;
310→    }
311→
312→    nlohmann::json schema_obj;
313→    schema_obj["encoding"] = topic_source_->schema_encoding();
314→    schema_obj["definition"] = schema;
315→    schemas[topic_name] = schema_obj;
316→
317→    spdlog::info("Client '{}' subscribed to topic '{}' (type: {})", client_id, topic_name, topic_type);
318→  }
319→
320→  // Update rates for topics that were already subscribed but may have a new rate
321→  for (const auto& [topic, rate] : requested_topics) {
322→    if (current_subs.find(topic) != current_subs.end()) {
323→      session_manager_->add_subscription(client_id, topic, rate);
324→    }
325→  }
326→
327→  // Build response
328→  json response;
329→  if (failures.empty()) {
330→    response["status"] = "success";
331→  } else if (schemas.empty()) {
332→    response["status"] = "error";
333→    response["error_code"] = "ALL_SUBSCRIPTIONS_FAILED";
334→    response["message"] = "Failed to subscribe to all requested topics";
335→  } else {
336→    response["status"] = "partial_success";
337→    response["message"] = "Some subscriptions failed";
338→  }
339→
340→  response["schemas"] = schemas;
341→  if (!failures.empty()) {
342→    response["failures"] = failures;
343→  }
344→
345→  // Include rate limits in response for topics with non-zero rates
346→  json rate_limits = json::object();
347→  auto updated_subs = session_manager_->get_subscriptions(client_id);
348→  for (const auto& [topic, rate] : updated_subs) {
349→    if (rate > 0.0) {
350→      rate_limits[topic] = rate;
351→    }
352→  }
353→  if (!rate_limits.empty()) {
354→    response["rate_limits"] = rate_limits;
355→  }
356→
357→  inject_response_fields(response, request);
358→
359→  return response.dump();
360→}
361→
362→std::string BridgeServer::handle_unsubscribe(const std::string& client_id, const nlohmann::json& request) {
363→  if (!session_manager_->session_exists(client_id)) {
364→    session_manager_->create_session(client_id);
365→    spdlog::info("Created new session for client '{}'", client_id);
366→  }
367→
368→  session_manager_->update_heartbeat(client_id);
369→
370→  if (!request.contains("topics") || !request["topics"].is_array()) {
371→    return create_error_response("INVALID_REQUEST", "Missing or invalid 'topics' array", request);
372→  }
373→
374→  auto current_subs = session_manager_->get_subscriptions(client_id);
375→
376→  std::vector<std::string> removed;
377→
378→  for (const auto& topic_item : request["topics"]) {
379→    std::string topic_name;
380→    if (topic_item.is_string()) {
381→      topic_name = topic_item.get<std::string>();
382→    } else if (topic_item.is_object() && topic_item.contains("name") && topic_item["name"].is_string()) {
383→      topic_name = topic_item["name"].get<std::string>();
384→    } else {
385→      continue;
386→    }
387→
388→    if (current_subs.find(topic_name) != current_subs.end()) {
389→      subscription_manager_->unsubscribe(topic_name);
390→      current_subs.erase(topic_name);
391→      removed.push_back(topic_name);
392→
393→      spdlog::info("Client '{}' unsubscribed from topic '{}'", client_id, topic_name);
394→    }
395→  }
396→
397→  session_manager_->update_subscriptions(client_id, current_subs);
398→
399→  json response;
400→  response["status"] = "success";
401→  response["removed"] = removed;
402→  inject_response_fields(response, request);
403→
404→  return response.dump();
405→}
