424→std::string BridgeServer::handle_pause(const std::string& client_id, const nlohmann::json& request) {
425→  if (!session_manager_->session_exists(client_id)) {
426→    session_manager_->create_session(client_id);
427→    spdlog::info("Created new session for client '{}'", client_id);
428→  }
429→
430→  session_manager_->update_heartbeat(client_id);
431→
432→  if (session_manager_->is_paused(client_id)) {
433→    spdlog::debug("Client '{}' already paused", client_id);
434→    json response;
435→    response["status"] = "ok";
436→    response["paused"] = true;
437→    inject_response_fields(response, request);
438→    return response.dump();
439→  }
440→
441→  session_manager_->set_paused(client_id, true);
442→
443→  // Decrement ref counts for all subscribed topics
444→  auto subs = session_manager_->get_subscriptions(client_id);
445→  for (const auto& [topic, rate] : subs) {
446→    subscription_manager_->unsubscribe(topic);
447→    spdlog::debug("Decremented ref count for topic '{}' (client '{}' paused)", topic, client_id);
448→  }
449→
450→  spdlog::info("Client '{}' paused ({} topics refs decremented)", client_id, subs.size());
451→
452→  json response;
453→  response["status"] = "ok";
454→  response["paused"] = true;
455→  inject_response_fields(response, request);
456→  return response.dump();
457→}
458→
459→std::string BridgeServer::handle_resume(const std::string& client_id, const nlohmann::json& request) {
460→  if (!session_manager_->session_exists(client_id)) {
461→    session_manager_->create_session(client_id);
462→    spdlog::info("Created new session for client '{}'", client_id);
463→  }
464→
465→  session_manager_->update_heartbeat(client_id);
466→
467→  if (!session_manager_->is_paused(client_id)) {
468→    spdlog::debug("Client '{}' not paused", client_id);
469→    json response;
470→    response["status"] = "ok";
471→    response["paused"] = false;
472→    inject_response_fields(response, request);
473→    return response.dump();
474→  }
475→
476→  session_manager_->set_paused(client_id, false);
477→
478→  // Build topic name → type lookup for subscribe calls
479→  auto available_topics = topic_source_->get_topics();
480→  std::unordered_map<std::string, std::string> topic_types;
481→  for (const auto& t : available_topics) {
482→    topic_types[t.name] = t.type;
483→  }
484→
485→  // Increment ref counts for all subscribed topics
486→  auto subs = session_manager_->get_subscriptions(client_id);
487→  std::vector<std::string> failed_topics;
488→  for (const auto& [topic, rate] : subs) {
489→    auto type_it = topic_types.find(topic);
490→    if (type_it == topic_types.end()) {
491→      spdlog::warn("Topic '{}' no longer exists, cannot re-subscribe for client '{}'", topic, client_id);
492→      failed_topics.push_back(topic);
493→      continue;
494→    }
495→    bool ok = subscription_manager_->subscribe(topic, type_it->second);
496→    if (ok) {
497→      spdlog::debug("Incremented ref count for topic '{}' (client '{}' resumed)", topic, client_id);
498→    } else {
499→      spdlog::warn("Topic '{}' subscription failed on resume for client '{}'", topic, client_id);
500→      failed_topics.push_back(topic);
501→    }
502→  }
503→
504→  // Remove failed topics from session to prevent ref-count underflow on disconnect
505→  for (const auto& topic : failed_topics) {
506→    session_manager_->remove_subscription(client_id, topic);
507→  }
508→
509→  spdlog::info("Client '{}' resumed ({} topics re-subscribed, {} failed)", client_id,
510→               subs.size() - failed_topics.size(), failed_topics.size());
511→
512→  json response;
513→  response["status"] = "ok";
514→  response["paused"] = false;
515→  inject_response_fields(response, request);
516→  return response.dump();
517→}
