550→void BridgeServer::cleanup_session(const std::string& client_id) {
551→  std::lock_guard<std::mutex> lock(cleanup_mutex_);
552→
553→  if (!session_manager_->session_exists(client_id)) {
554→    return;
555→  }
556→
557→  auto subscriptions = session_manager_->get_subscriptions(client_id);
558→  bool was_paused = session_manager_->is_paused(client_id);
559→
560→  // Unsubscribe from all topics (only if not paused — paused clients already decremented ref counts)
561→  if (!was_paused) {
562→    for (const auto& [topic, rate] : subscriptions) {
563→      subscription_manager_->unsubscribe(topic);
564→      spdlog::debug("Unsubscribed client '{}' from topic '{}'", client_id, topic);
565→    }
566→  }
567→
568→  session_manager_->remove_session(client_id);
569→
570→  {
571→    std::lock_guard<std::mutex> sent_lock(last_sent_mutex_);
572→    last_sent_times_.erase(client_id);
573→  }
574→
575→  spdlog::info("Cleaned up session for client '{}' ({} topics unsubscribed)", client_id, subscriptions.size());
576→}
