600→void BridgeServer::publish_aggregated_messages() {
601→  if (!initialized_) {
602→    return;
603→  }
604→
605→  std::unordered_map<std::string, std::deque<BufferedMessage>> messages;
606→  message_buffer_->move_messages(messages);
607→
608→  if (messages.empty()) {
609→    return;
610→  }
611→
612→  try {
613→    auto active_sessions = session_manager_->get_active_sessions();
614→    if (active_sessions.empty()) {
615→      return;
616→    }
617→
618→    // Group clients by subscription config (topic + rate) to avoid redundant serialization.
619→    using GroupKey = std::map<std::string, int>;
620→    std::map<GroupKey, std::vector<std::string>> subscription_groups;
621→    std::unordered_map<std::string, std::unordered_map<std::string, double>> client_subs;
622→
623→    for (const auto& client_id : active_sessions) {
624→      auto subs = session_manager_->get_subscriptions(client_id);
625→      if (subs.empty()) {
626→        continue;
627→      }
628→      GroupKey key;
629→      for (const auto& [topic, rate_hz] : subs) {
630→        key[topic] = static_cast<int>(rate_hz * 1000);
631→      }
632→      subscription_groups[key].push_back(client_id);
633→      client_subs[client_id] = std::move(subs);
634→    }
635→
636→    size_t total_msg_count = 0;
637→    size_t total_bytes = 0;
638→    std::unordered_map<std::string, uint64_t> forward_counts;
639→
640→    // Collect paused state outside of last_sent_mutex_ to avoid lock ordering issues.
641→    std::unordered_map<std::string, bool> paused_state;
642→    for (const auto& [group_key, client_ids] : subscription_groups) {
643→      for (const auto& client_id : client_ids) {
644→        paused_state[client_id] = session_manager_->is_paused(client_id);
645→      }
646→    }
647→
648→    // Per-group serialized frames, built under last_sent_mutex_ for rate limiting
649→    struct GroupFrame {
650→      std::vector<uint8_t> compressed_data;
651→      size_t msg_count;
652→      std::vector<std::string> client_ids;
653→    };
654→    std::vector<GroupFrame> frames;
655→
656→    {
657→      std::lock_guard<std::mutex> sent_lock(last_sent_mutex_);
658→
659→      for (const auto& [group_key, client_ids] : subscription_groups) {
660→        AggregatedMessageSerializer serializer;
661→        size_t group_msg_count = 0;
662→
663→        const auto& representative_subs = client_subs[client_ids.front()];
664→        auto& rep_last_sent = last_sent_times_[client_ids.front()];
665→
666→        for (const auto& [topic, msgs] : messages) {
667→          auto sub_it = representative_subs.find(topic);
668→          if (sub_it == representative_subs.end()) {
669→            continue;
670→          }
671→
672→          double rate_hz = sub_it->second;
673→          int rate_mhz = static_cast<int>(rate_hz * 1000);
674→
675→          if (rate_mhz == 0) {
676→            for (const auto& msg : msgs) {
677→              serializer.serialize_message(topic, msg.timestamp_ns, msg.data->data(), msg.data->size());
678→              group_msg_count++;
679→              forward_counts[topic]++;
680→            }
681→          } else {
682→            uint64_t min_interval_ns = static_cast<uint64_t>(1'000'000'000'000) / static_cast<uint64_t>(rate_mhz);
683→            uint64_t last_sent = rep_last_sent[topic];
684→
685→            for (const auto& msg : msgs) {
686→              if (msg.timestamp_ns >= last_sent + min_interval_ns) {
687→                serializer.serialize_message(topic, msg.timestamp_ns, msg.data->data(), msg.data->size());
688→                last_sent = msg.timestamp_ns;
689→                group_msg_count++;
690→                forward_counts[topic]++;
691→              }
692→            }
693→            rep_last_sent[topic] = last_sent;
694→          }
695→        }
696→
697→        if (group_msg_count == 0) {
698→          continue;
699→        }
700→
701→        GroupFrame frame;
702→        frame.compressed_data = serializer.finalize();
703→        frame.msg_count = group_msg_count;
704→        frame.client_ids = client_ids;
705→
706→        // Propagate rate-limiting state to other clients in the group
707→        for (const auto& client_id : client_ids) {
708→          if (client_id != client_ids.front()) {
709→            last_sent_times_[client_id] = rep_last_sent;
710→          }
711→        }
712→
713→        frames.push_back(std::move(frame));
714→      }
715→    }  // last_sent_mutex_ released here
716→
717→    // Send frames outside of any lock
718→    for (const auto& frame : frames) {
719→      bool any_sent = false;
720→      for (const auto& client_id : frame.client_ids) {
721→        auto it = paused_state.find(client_id);
722→        if (it != paused_state.end() && it->second) {
723→          continue;
724→        }
725→        if (middleware_->send_binary(client_id, frame.compressed_data)) {
726→          any_sent = true;
727→        } else {
728→          spdlog::debug("Failed to send binary frame to client '{}'", client_id);
729→        }
730→      }
731→
732→      if (any_sent) {
733→        total_msg_count += frame.msg_count;
734→        total_bytes += frame.compressed_data.size();
735→      }
736→    }
737→
738→    if (total_msg_count > 0) {
739→      std::lock_guard<std::mutex> lock(stats_mutex_);
740→      total_messages_published_ += total_msg_count;
741→      total_bytes_published_ += total_bytes;
742→      publish_cycles_++;
743→      for (const auto& [topic, count] : forward_counts) {
744→        topic_forward_counts_[topic] += count;
745→      }
746→    }
747→  } catch (const std::exception& e) {
748→    spdlog::error("Error publishing aggregated messages: {}", e.what());
749→  }
750→}
