 34→
 35→tl::expected<void, std::string> WebSocketMiddleware::initialize(uint16_t port) {
 36→  std::lock_guard<std::mutex> lock(state_mutex_);
 37→
 38→  if (initialized_) {
 39→    return tl::unexpected<std::string>("WebSocket middleware already initialized");
 40→  }
 41→
 42→  server_ = std::make_shared<ix::WebSocketServer>(port, "0.0.0.0");
 43→
 44→  server_->setOnClientMessageCallback([this](
 45→                                          std::shared_ptr<ix::ConnectionState> connection_state,
 46→                                          ix::WebSocket& web_socket, const ix::WebSocketMessagePtr& msg) {
 47→    {
 48→      std::lock_guard<std::mutex> state_lock(state_mutex_);
 49→      if (!initialized_) {
 50→        return;
 51→      }
 52→    }
 53→
 54→    std::string client_id = connection_state->getId();
 55→
 56→    if (msg->type == ix::WebSocketMessageType::Open) {
 57→      {
 58→        std::lock_guard<std::mutex> clients_lock(clients_mutex_);
 59→        for (const auto& client : server_->getClients()) {
 60→          if (client.get() == &web_socket) {
 61→            clients_[client_id] = client;
 62→            break;
 63→          }
 64→        }
 65→      }
 66→
 67→      ConnectionCallback cb;
 68→      {
 69→        std::lock_guard<std::mutex> state_lock(state_mutex_);
 70→        cb = on_connect_;
 71→      }
 72→      if (cb) {
 73→        cb(client_id);
 74→      }
 75→
 76→    } else if (msg->type == ix::WebSocketMessageType::Close) {
 77→      ConnectionCallback cb;
 78→      {
 79→        std::lock_guard<std::mutex> state_lock(state_mutex_);
 80→        cb = on_disconnect_;
 81→      }
 82→      if (cb) {
 83→        cb(client_id);
 84→      }
 85→
 86→      {
 87→        std::lock_guard<std::mutex> clients_lock(clients_mutex_);
 88→        clients_.erase(client_id);
 89→      }
 90→
 91→    } else if (msg->type == ix::WebSocketMessageType::Message) {
 92→      if (!msg->binary) {
 93→        IncomingRequest req;
 94→        req.client_id = client_id;
 95→        req.data.assign(msg->str.begin(), msg->str.end());
 96→
 97→        {
 98→          std::lock_guard<std::mutex> queue_lock(queue_mutex_);
 99→          if (incoming_queue_.size() >= kMaxIncomingQueueSize) {
100→            spdlog::warn("Incoming queue full ({} messages), dropping message from client '{}'",
101→                         kMaxIncomingQueueSize, client_id);
102→            return;
103→          }
104→          incoming_queue_.push(std::move(req));
105→        }
106→        queue_cv_.notify_one();
107→      }
108→    }
109→  });
110→
111→  auto listen_result = server_->listen();
112→  if (!listen_result.first) {
113→    server_.reset();
114→    return tl::unexpected<std::string>(
115→        "Failed to listen on port " + std::to_string(port) + ": " + listen_result.second);
116→  }
117→
118→  server_->start();
119→  initialized_ = true;
120→
121→  return {};
122→}
123→
124→void WebSocketMiddleware::shutdown() {
125→  std::shared_ptr<ix::WebSocketServer> server_to_stop;
126→
127→  {
128→    std::lock_guard<std::mutex> lock(state_mutex_);
129→
130→    if (!initialized_) {
131→      return;
132→    }
133→
134→    initialized_ = false;
135→    on_connect_ = nullptr;
136→    on_disconnect_ = nullptr;
137→    server_to_stop = std::move(server_);
138→  }
139→
140→  queue_cv_.notify_all();
141→
142→  if (server_to_stop) {
143→    // Replace the message callback with a no-op before stopping. The original
144→    // callback captures `this`, so it must not fire after the WebSocketMiddleware
145→    // instance is destroyed (which can happen if the stop thread is detached on timeout).
146→    server_to_stop->setOnClientMessageCallback(
147→        [](std::shared_ptr<ix::ConnectionState>, ix::WebSocket&, const ix::WebSocketMessagePtr&) {});
148→
149→    // Initiate graceful close on all connected clients before calling stop().
150→    spdlog::debug("[shutdown] Pre-closing {} WebSocket client(s)...", server_to_stop->getClients().size());
151→    for (const auto& client : server_to_stop->getClients()) {
152→      client->close();
153→    }
154→
155→    // Run stop() on a dedicated thread with a timeout.
156→    spdlog::debug("[shutdown] Starting server stop thread...");
157→    auto done = std::make_shared<std::atomic<bool>>(false);
158→    std::thread stop_thread([server_to_stop, done]() {
159→      server_to_stop->stop();
160→      done->store(true);
161→    });
162→
163→    auto start = std::chrono::steady_clock::now();
164→    auto deadline = start + std::chrono::seconds(kShutdownTimeoutSeconds);
165→    while (!done->load() && std::chrono::steady_clock::now() < deadline) {
166→      std::this_thread::sleep_for(std::chrono::milliseconds(50));
167→    }
168→    auto elapsed_ms =
169→        std::chrono::duration_cast<std::chrono::milliseconds>(std::chrono::steady_clock::now() - start).count();
170→
171→    if (done->load()) {
172→      stop_thread.join();
173→      spdlog::debug("[shutdown] Server stop completed (took {}ms)", elapsed_ms);
174→    } else {
175→      // Timeout reached. Detach the thread and let it finish in the background.
176→      // The thread captures server_to_stop by shared_ptr, so the server
177→      // will be destroyed when stop() finishes and the thread exits.
178→      // The message callback was already cleared above, so no use-after-free.
179→      spdlog::warn(
180→          "[shutdown] Server stop timed out after {}s ({}ms elapsed), detaching shutdown thread",
181→          kShutdownTimeoutSeconds, elapsed_ms);
182→      stop_thread.detach();
183→    }
184→  }
185→
186→  {
187→    std::lock_guard<std::mutex> clients_lock(clients_mutex_);
188→    clients_.clear();
189→  }
190→
191→  {
192→    std::lock_guard<std::mutex> queue_lock(queue_mutex_);
193→    std::queue<IncomingRequest> empty;
194→    std::swap(incoming_queue_, empty);
195→  }
196→}
197→
198→bool WebSocketMiddleware::receive_request(std::vector<uint8_t>& data, std::string& client_identity) {
199→  {
200→    std::lock_guard<std::mutex> state_lock(state_mutex_);
201→    if (!initialized_) {
202→      return false;
203→    }
204→  }
205→
206→  std::unique_lock<std::mutex> lock(queue_mutex_);
207→
208→  if (!queue_cv_.wait_for(
209→          lock, std::chrono::milliseconds(kReceiveTimeoutMs), [this]() { return !incoming_queue_.empty(); })) {
210→    return false;
211→  }
212→
213→  auto req = std::move(incoming_queue_.front());
214→  incoming_queue_.pop();
215→
216→  data = std::move(req.data);
217→  client_identity = std::move(req.client_id);
218→  return true;
219→}
220→
221→bool WebSocketMiddleware::send_reply(const std::string& client_identity, const std::vector<uint8_t>& data) {
222→  std::shared_ptr<ix::WebSocket> ws;
223→  {
224→    std::lock_guard<std::mutex> lock(clients_mutex_);
225→    auto it = clients_.find(client_identity);
226→    if (it == clients_.end() || !it->second) {
227→      return false;
228→    }
229→    ws = it->second;
230→  }
231→
232→  std::string text_data(data.begin(), data.end());
233→  auto send_info = ws->send(text_data);
234→  return send_info.success;
235→}
236→
237→bool WebSocketMiddleware::send_binary(const std::string& client_identity, const std::vector<uint8_t>& data) {
238→  std::shared_ptr<ix::WebSocket> ws;
239→  {
240→    std::lock_guard<std::mutex> lock(clients_mutex_);
241→    auto it = clients_.find(client_identity);
242→    if (it == clients_.end() || !it->second) {
243→      return false;
244→    }
245→    ws = it->second;
246→  }
247→
248→  std::string binary_data(reinterpret_cast<const char*>(data.data()), data.size());
249→  auto send_info = ws->sendBinary(binary_data);
250→  return send_info.success;
251→}
252→
253→bool WebSocketMiddleware::publish_data(const std::vector<uint8_t>& data) {
254→  std::vector<std::shared_ptr<ix::WebSocket>> clients_copy;
255→  {
256→    std::lock_guard<std::mutex> lock(clients_mutex_);
257→    if (clients_.empty()) {
258→      return false;
259→    }
260→    clients_copy.reserve(clients_.size());
261→    for (const auto& [client_id, ws] : clients_) {
262→      if (ws) {
263→        clients_copy.push_back(ws);
264→      }
265→    }
266→  }
267→
268→  std::string binary_data(reinterpret_cast<const char*>(data.data()), data.size());
269→  bool any_sent = false;
270→
271→  for (const auto& ws : clients_copy) {
272→    auto send_info = ws->sendBinary(binary_data);
273→    if (send_info.success) {
274→      any_sent = true;
275→    }
276→  }
277→
278→  return any_sent;
279→}
280→
281→bool WebSocketMiddleware::is_ready() const {
282→  std::lock_guard<std::mutex> lock(state_mutex_);
283→  return initialized_;
284→}
