 28→bool SessionManager::create_session(const std::string& client_id) {
 29→  std::lock_guard<std::mutex> lock(mutex_);
 30→
 31→  if (sessions_.find(client_id) != sessions_.end()) {
 32→    return false;
 33→  }
 34→
 35→  Session session;
 36→  session.client_id = client_id;
 37→  session.created_at = std::chrono::steady_clock::now();
 38→  session.last_heartbeat = session.created_at;
 39→
 40→  sessions_[client_id] = session;
 41→  return true;
 42→}
