 44→bool SessionManager::update_heartbeat(const std::string& client_id) {
 45→  std::lock_guard<std::mutex> lock(mutex_);
 46→
 47→  auto it = sessions_.find(client_id);
 48→  if (it == sessions_.end()) {
 49→    return false;
 50→  }
 51→
 52→  it->second.last_heartbeat = std::chrono::steady_clock::now();
 53→  return true;
 54→}
