127→std::vector<std::string> SessionManager::get_timed_out_sessions() {
128→  std::lock_guard<std::mutex> lock(mutex_);
129→
130→  std::vector<std::string> timed_out_clients;
131→  auto now = std::chrono::steady_clock::now();
132→
133→  for (const auto& [client_id, session] : sessions_) {
134→    auto time_since_heartbeat = now - session.last_heartbeat;
135→    if (time_since_heartbeat > timeout_duration_) {
136→      timed_out_clients.push_back(client_id);
137→    }
138→  }
139→
140→  return timed_out_clients;
141→}
