146→  std::vector<std::string> active_sessions;
147→  active_sessions.reserve(sessions_.size());
148→
149→  for (const auto& [client_id, session] : sessions_) {
150→    active_sessions.push_back(client_id);
151→  }
152→
153→  return active_sessions;
154→}
